<script setup lang="ts">
import{onMounted,reactive,ref}from'vue';import{api}from'@/services/api';type Product={id:string;name:string;slug:string;sku:string;description:string;shortDescription:string;type:string;status:string;price:number;compareAtPrice?:number;currency:string;category?:string;brand?:string;featuredImageUrl?:string;featured:boolean;trackInventory:boolean;allowBackorder:boolean;stockQuantity:number;lowStockThreshold:number;inStock:boolean;variants:any[]};const tab=ref<'dashboard'|'products'|'inventory'|'movements'>('dashboard');const data=ref<any>({featured:[],alerts:[]});const products=ref<Product[]>([]);const movements=ref<any[]>([]);const editor=ref(false);const inventory=ref<Product|null>(null);const draft=reactive<any>({});const adjust=reactive({type:'ADD',quantity:0,reason:''});const empty=()=>({id:'',name:'',slug:'',sku:'',description:'',shortDescription:'',type:'PHYSICAL',status:'ACTIVE',price:0,compareAtPrice:null,currency:'USD',category:'',brand:'',featuredImageUrl:'',gallery:[],attributes:{},seo:{},featured:false,trackInventory:true,allowBackorder:false,stockQuantity:0,lowStockThreshold:5,weightGrams:null,digitalUrl:'',variants:[]});async function load(){data.value=await api('/api/admin/store/dashboard');const [productPage,movementPage]=await Promise.all([api<any>('/api/admin/store/products?size=100'),api<any>('/api/admin/store/inventory/movements?size=100')]);products.value=productPage.content;movements.value=movementPage.content}function edit(p?:Product){Object.assign(draft,empty(),p||{});draft.variants=Array.isArray(draft.variants)?draft.variants.map((v:any)=>({...v})):[];editor.value=true}function addVariant(){draft.variants.push({id:null,name:'',sku:'',price:null,stockQuantity:0,optionValues:'',imageUrl:'',active:true})}function removeVariant(index:number){draft.variants.splice(index,1)}async function save(){await api(draft.id?`/api/admin/store/products/${draft.id}`:'/api/admin/store/products',{method:draft.id?'PUT':'POST',body:JSON.stringify(draft)});editor.value=false;await load()}async function saveAdjustment(){if(!inventory.value)return;await api(`/api/admin/store/products/${inventory.value.id}/inventory`,{method:'POST',body:JSON.stringify(adjust)});inventory.value=null;await load()}const money=(v:number,c='USD')=>new Intl.NumberFormat('es-HN',{style:'currency',currency:c}).format(v||0);onMounted(load);
</script>

<template>
<div class="space-y-6"><header class="flex flex-wrap items-end justify-between gap-4"><div><span class="eyebrow">TRASTSTORE</span><h1 class="text-3xl font-black">Tienda online</h1><p class="text-slate-500">Catálogo, variantes, inventario, productos digitales y fulfillment.</p></div><button class="button" @click="tab='products';edit()">+ Nuevo producto</button></header><nav class="plugin-tabs"><button v-for="i in [{id:'dashboard',label:'Resumen'},{id:'products',label:'Productos'},{id:'inventory',label:'Inventario'},{id:'movements',label:'Movimientos'}]" :key="i.id" :class="{active:tab===i.id}" @click="tab=i.id as any">{{i.label}}</button></nav><section v-if="tab==='dashboard'" class="space-y-6"><div class="grid gap-4 md:grid-cols-5"><article class="metric-card"><span>Productos</span><strong>{{data.products}}</strong></article><article class="metric-card"><span>Activos</span><strong>{{data.active}}</strong></article><article class="metric-card"><span>Stock bajo</span><strong>{{data.lowStock}}</strong></article><article class="metric-card"><span>Agotados</span><strong>{{data.outOfStock}}</strong></article><article class="metric-card"><span>Variantes</span><strong>{{data.variants}}</strong></article></div><div class="grid gap-6 xl:grid-cols-2"><section class="panel"><h2 class="text-xl font-bold">Productos destacados</h2><div class="mt-4 grid gap-3 sm:grid-cols-2"><article v-for="p in data.featured" :key="p.id" class="rounded-xl border p-4"><b>{{p.name}}</b><p class="text-sm text-slate-500">{{p.category||'Sin categoría'}}</p><strong class="mt-2 block text-violet-700">{{money(p.price,p.currency)}}</strong></article></div></section><section class="panel"><h2 class="text-xl font-bold">Alertas de inventario</h2><div v-for="p in data.alerts" :key="p.id" class="mt-3 flex items-center justify-between rounded-xl bg-amber-50 p-4"><div><b>{{p.name}}</b><small class="block">{{p.sku}}</small></div><span class="status-pill warning">{{p.stockQuantity}} unidades</span></div></section></div></section><section v-else-if="tab==='products'" class="panel"><div class="overflow-x-auto"><table class="data-table"><thead><tr><th>Producto</th><th>SKU</th><th>Tipo</th><th>Precio</th><th>Inventario</th><th>Estado</th><th></th></tr></thead><tbody><tr v-for="p in products" :key="p.id"><td><b>{{p.name}}</b><small>{{p.category||'Sin categoría'}}</small></td><td>{{p.sku}}</td><td>{{p.type}}</td><td>{{money(p.price,p.currency)}}</td><td>{{p.trackInventory?p.stockQuantity:'Sin control'}}</td><td><span :class="['status-pill',p.status==='ACTIVE'?'ok':'muted']">{{p.status}}</span></td><td><button class="text-link" @click="edit(p)">Editar</button></td></tr></tbody></table></div></section><section v-else-if="tab==='inventory'" class="panel"><div class="grid gap-4 lg:grid-cols-3"><article v-for="p in products.filter(x=>x.trackInventory)" :key="p.id" class="rounded-2xl border p-5"><div class="flex justify-between"><div><b>{{p.name}}</b><small class="block">{{p.sku}}</small></div><strong :class="p.stockQuantity<=p.lowStockThreshold?'text-rose-600':'text-emerald-600'">{{p.stockQuantity}}</strong></div><button class="button secondary small mt-4" @click="inventory=p;Object.assign(adjust,{type:'ADD',quantity:0,reason:''})">Ajustar</button></article></div></section><section v-else class="panel"><div class="overflow-x-auto"><table class="data-table"><thead><tr><th>Fecha</th><th>Producto</th><th>Tipo</th><th>Cantidad</th><th>Motivo</th><th>Referencia</th></tr></thead><tbody><tr v-for="m in movements" :key="m.id"><td>{{new Date(m.createdAt).toLocaleString()}}</td><td><b>{{m.productName}}</b><small v-if="m.variantName">{{m.variantName}}</small></td><td><span class="status-pill">{{m.type}}</span></td><td :class="m.quantity<0?'text-rose-600':'text-emerald-600'">{{m.quantity>0?'+':''}}{{m.quantity}}</td><td>{{m.reason}}</td><td>{{m.referenceType||'—'}} {{m.referenceId||''}}</td></tr></tbody></table></div></section><div v-if="editor" class="modal-backdrop"><form class="modal-card max-w-4xl" @submit.prevent="save"><header><div><span class="eyebrow">CATÁLOGO</span><h2 class="text-2xl font-bold">{{draft.id?'Editar':'Nuevo'}} producto</h2></div><button type="button" class="icon-button" @click="editor=false">×</button></header><div class="grid max-h-[65vh] gap-4 overflow-y-auto p-1 md:grid-cols-2"><label>Nombre<input v-model="draft.name" required></label><label>SKU<input v-model="draft.sku" required></label><label>Slug<input v-model="draft.slug"></label><label>Categoría<input v-model="draft.category"></label><label>Tipo<select v-model="draft.type"><option>PHYSICAL</option><option>DIGITAL</option><option>SERVICE</option><option>EXTERNAL</option></select></label><label>Estado<select v-model="draft.status"><option>DRAFT</option><option>ACTIVE</option><option>ARCHIVED</option></select></label><label>Precio<input v-model.number="draft.price" type="number" step="0.01"></label><label>Precio anterior<input v-model.number="draft.compareAtPrice" type="number" step="0.01"></label><label class="md:col-span-2">Descripción corta<input v-model="draft.shortDescription"></label><label class="md:col-span-2">Descripción<textarea v-model="draft.description"></textarea></label><label>Imagen destacada<input v-model="draft.featuredImageUrl"></label><label>Marca<input v-model="draft.brand"></label><label>Existencia<input v-model.number="draft.stockQuantity" type="number"></label><label>Alerta mínima<input v-model.number="draft.lowStockThreshold" type="number"></label><label class="check-row"><input v-model="draft.featured" type="checkbox">Destacado</label><label class="check-row"><input v-model="draft.trackInventory" type="checkbox">Controlar inventario</label><label class="check-row"><input v-model="draft.allowBackorder" type="checkbox">Permitir sobreventa</label><section class="md:col-span-2 rounded-2xl border border-slate-200 p-4"><div class="flex items-center justify-between"><div><h3 class="font-bold">Variantes</h3><p class="text-sm text-slate-500">Tamaños, colores, licencias o presentaciones con SKU, precio e inventario propio.</p></div><button type="button" class="button secondary small" @click="addVariant">Agregar variante</button></div><div class="mt-4 space-y-3"><article v-for="(variant,index) in draft.variants" :key="variant.id||index" class="grid gap-3 rounded-xl bg-slate-50 p-4 md:grid-cols-3"><label>Nombre<input v-model="variant.name" required></label><label>SKU<input v-model="variant.sku" required></label><label>Opciones<input v-model="variant.optionValues" placeholder="Color=Negro;Talla=M"></label><label>Precio<input v-model.number="variant.price" type="number" step="0.01" placeholder="Heredar"></label><label>Existencia<input v-model.number="variant.stockQuantity" type="number"></label><label class="check-row"><input v-model="variant.active" type="checkbox">Activa</label><div class="md:col-span-3"><button type="button" class="text-link danger" @click="removeVariant(index)">Eliminar variante</button></div></article><p v-if="!draft.variants.length" class="text-sm text-slate-500">El producto no tiene variantes.</p></div></section></div><footer><button type="button" class="button secondary" @click="editor=false">Cancelar</button><button class="button">Guardar producto</button></footer></form></div><div v-if="inventory" class="modal-backdrop"><form class="modal-card max-w-lg" @submit.prevent="saveAdjustment"><header><h2 class="text-xl font-bold">Ajustar {{inventory.name}}</h2><button type="button" class="icon-button" @click="inventory=null">×</button></header><label>Operación<select v-model="adjust.type"><option value="ADD">Sumar o restar</option><option value="SET">Establecer cantidad</option></select></label><label>Cantidad<input v-model.number="adjust.quantity" type="number" required></label><label>Motivo<input v-model="adjust.reason" required></label><footer><button class="button">Aplicar ajuste</button></footer></form></div></div></template>
